		private void optimizeJoinReplacement(TupleExpr replaceTarget, Join join,
				List<Filter> additionalDeferredFilters) {
			Set<String> origBoundVars = boundVars;
			try {
				boundVars = new HashSet<>(boundVars);

				CollectedJoinArgs collectedJoinArgs = collectJoinArgsForOrdering(join);
				collectedJoinArgs.deferredFilters.addAll(additionalDeferredFilters);
				visitDeferredFilterConditions(collectedJoinArgs.deferredFilters, origBoundVars);
				OrderedJoinPlan orderedJoinPlan = orderJoinArgsPreservingSeparators(collectedJoinArgs, origBoundVars);
				TupleExpr root = buildOrderedJoinPlanRoot(orderedJoinPlan);

				if (root != null) {
					root = reapplyDeferredFilters(root, orderedJoinPlan.rootDeferredFilters);

					if (TupleExprs.isVariableScopeChange(replaceTarget)) {
						((AbstractQueryModelNode) root).setVariableScopeChange(true);
					}

					replaceTarget.replaceWith(root);
				} else {
					throw new IllegalStateException("Expected at least one join argument");
				}
			} finally {
				boundVars = origBoundVars;
			}
		}

		private void visitDeferredFilterConditions(List<Filter> filters, Set<String> outerBoundVars) {
			for (Filter filter : filters) {
				Set<String> origBoundVars = boundVars;
				try {
					boundVars = new HashSet<>(outerBoundVars);
					boundVars.addAll(filter.getArg().getAssuredBindingNames());
					filter.getCondition().visit(this);
				} finally {
					boundVars = origBoundVars;
				}
			}
		}

		private CollectedJoinArgs collectJoinArgsForOrdering(Join node) {
			CollectedJoinArgs collectedJoinArgs = new CollectedJoinArgs();
			collectJoinArgsForOrdering(node, collectedJoinArgs.joinArgs, collectedJoinArgs.deferredFilters);
			return collectedJoinArgs;
		}

		private void collectJoinArgsForOrdering(Join node, List<TupleExpr> joinArgs) {
			collectJoinArgsForOrdering(node, joinArgs, new ArrayList<>());
		}

		private void collectJoinArgsForOrdering(Join node, List<TupleExpr> joinArgs, List<Filter> deferredFilters) {
			collectJoinArgsForOrdering(node.getLeftArg(), joinArgs, deferredFilters);
			collectJoinArgsForOrdering(node.getRightArg(), joinArgs, deferredFilters);
		}

		private void collectJoinArgsForOrdering(TupleExpr tupleExpr, List<TupleExpr> joinArgs,
				List<Filter> deferredFilters) {
			if (tupleExpr instanceof Join && !isJoinOrderSeparator(tupleExpr)) {
				Join join = (Join) tupleExpr;
				collectJoinArgsForOrdering(join.getLeftArg(), joinArgs, deferredFilters);
				collectJoinArgsForOrdering(join.getRightArg(), joinArgs, deferredFilters);
			} else if (tupleExpr instanceof Filter) {
				Filter filter = (Filter) tupleExpr;
				ArrayDeque<Filter> nestedFilters = new ArrayDeque<>();
				TupleExpr filterArg = unwrapJoinFilterChain(filter, nestedFilters);
				if (filterArg instanceof Join) {
					collectJoinArgsForOrdering(filterArg, joinArgs, deferredFilters);
					deferredFilters.addAll(nestedFilters);
				} else {
					joinArgs.add(tupleExpr);
				}
			} else {
				joinArgs.add(tupleExpr);
			}
		}

		private TupleExpr unwrapJoinFilterChain(Filter filter, ArrayDeque<Filter> nestedFilters) {
			TupleExpr current = filter;
			while (current instanceof Filter && !TupleExprs.isVariableScopeChange(current)) {
				Filter currentFilter = (Filter) current;
				nestedFilters.addFirst(currentFilter);
				current = currentFilter.getArg();
			}
			return current;
		}

		private TupleExpr reapplyDeferredFilters(TupleExpr root, List<DeferredFilter> deferredFilters) {
			TupleExpr current = root;
			for (DeferredFilter deferredFilter : deferredFilters) {
				Filter clone = deferredFilter.filter.clone();
				clone.setArg(current);
				annotateDeferredFilter(clone, deferredFilter, "root");
				current = clone;
			}
			return current;
		}

